; mon_pics.asm — Tier-2 wrapper for the generated pokémon front-sprite data.
;
; The compressed front .pic blobs and the dex-ordered pointer/length table
; (MonFrontPics, record = { dd flat_ptr, dd blob_len }, indexed by dex-1) are
; generated by tools/gen_mon_pics.py into assets/mon_pics.inc (Tier 1,
; machine-owned). This wrapper just gives them a loaded .data section + the
; MonFrontPics global so the front-sprite loader (src/gfx/pics.asm
; LoadFrontSpriteByMonIndex -> LoadMonFrontSprite) can resolve a mon's pic and
; feed it to the decompressor (src/gfx/uncompress.asm).
;
; Wired in only under -D MON_FRONT_PICS (Makefile). Without it, pics.asm falls
; back to the single embedded debug pic (pidgey.pic) for every mon.
;
; Build: nasm -f coff -I include/ -I . -o mon_pics.o src/data/mon_pics.asm

bits 32

global MonFrontPics

section .data
align 4
%include "assets/mon_pics.inc"
